import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

export default function Register() {
  const { register } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    name: '', email: '', password: '', role: 'patient',
    age: '', gender: '', phone: '', address: '', bloodGroup: '',
    specialization: '', licenseNumber: '',
  });

  const set = (field) => (e) => setForm({ ...form, [field]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await register(form);
      toast.success('Account created successfully');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center bg-light py-4">
      <div className="card p-4" style={{ width: '100%', maxWidth: 560 }}>
        <div className="text-center mb-4">
          <i className="bi bi-heart-pulse-fill text-danger fs-1" />
          <h4 className="mt-2">Create Account</h4>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="row g-3">
            <div className="col-md-6">
              <label className="form-label">Full Name *</label>
              <input className="form-control" value={form.name} onChange={set('name')} required />
            </div>
            <div className="col-md-6">
              <label className="form-label">Email *</label>
              <input type="email" className="form-control" value={form.email} onChange={set('email')} required />
            </div>
            <div className="col-md-6">
              <label className="form-label">Password *</label>
              <input type="password" className="form-control" value={form.password} onChange={set('password')} required minLength={6} />
            </div>
            <div className="col-md-6">
              <label className="form-label">Role *</label>
              <select className="form-select" value={form.role} onChange={set('role')}>
                <option value="patient">Patient</option>
                <option value="doctor">Doctor</option>
              </select>
            </div>
            <div className="col-md-4">
              <label className="form-label">Age</label>
              <input type="number" className="form-control" value={form.age} onChange={set('age')} />
            </div>
            <div className="col-md-4">
              <label className="form-label">Gender</label>
              <select className="form-select" value={form.gender} onChange={set('gender')}>
                <option value="">Select</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </div>
            <div className="col-md-4">
              <label className="form-label">Blood Group</label>
              <input className="form-control" value={form.bloodGroup} onChange={set('bloodGroup')} placeholder="e.g. A+" />
            </div>
            <div className="col-md-6">
              <label className="form-label">Phone</label>
              <input className="form-control" value={form.phone} onChange={set('phone')} />
            </div>
            <div className="col-md-6">
              <label className="form-label">Address</label>
              <input className="form-control" value={form.address} onChange={set('address')} />
            </div>
            {form.role === 'doctor' && (
              <>
                <div className="col-md-6">
                  <label className="form-label">Specialization</label>
                  <input className="form-control" value={form.specialization} onChange={set('specialization')} />
                </div>
                <div className="col-md-6">
                  <label className="form-label">License Number</label>
                  <input className="form-control" value={form.licenseNumber} onChange={set('licenseNumber')} />
                </div>
              </>
            )}
          </div>
          <button className="btn btn-primary w-100 mt-4" disabled={loading}>
            {loading ? <span className="spinner-border spinner-border-sm me-2" /> : null}
            Create Account
          </button>
        </form>
        <p className="text-center mt-3 mb-0">
          Already have an account? <Link to="/login">Sign in</Link>
        </p>
      </div>
    </div>
  );
}
